import play.api.mvc._
import slick.jdbc.PostgresProfile.api._
import scala.concurrent.ExecutionContext.Implicits.global

case class Product(id: Int, name: String, price: Double)

class ProductController @Inject()(cc: ControllerComponents)(implicit val db: Database) extends AbstractController(cc) {

  def searchProducts = Action.async { request =>
    val queryParams = request.queryString
    val sqlFragment = buildSqlFragment(queryParams)

    val query = sql"SELECT * FROM products WHERE $sqlFragment".as[Product]

    db.run(query).map { products =>
      Ok(views.html.products(products))
    }
  }

  private def buildSqlFragment(params: Map[String, Seq[String]]): String = {
    var conditions = List.empty[String]

    params.get("name").foreach(names => {
      names.foreach(name => conditions += s"name LIKE '%$name%'")
    })

    params.get("minPrice").foreach(prices => {
      prices.headOption.map(price => conditions += s"price >= $price")
    })

    params.get("maxPrice").foreach(prices => {
      prices.headOption.map(price => conditions += s"price <= $price")
    })

    if (conditions.nonEmpty) " AND ".join(conditions) else "1=1"
  }
}